('Hospedagem', 'Pousada do Rio', 'Aconchegante pousada familiar com vista para o Rio e café colonial.', 'Rua das Flores, 45', '(14) 3604-5678', 'www.pousadadorio.com', 'https://images.unsplash.com/photo-1510798831971-661eb04b3739?w=400&q=80', 4),
('Hospedagem', 'Chalés Recanto do Pescador', 'Chalés rústicos com estrutura para pesca e churrasqueira.', 'Estrada do Rio, Km 3', '(14) 3604-9012', NULL, 'https://images.unsplash.com/photo-1449158743715-0a90ebb6d2d8?w=400&q=80', 4),
('Gastronomia', 'Restaurante Peixe Vivo', 'Especializado em peixes do Rio, com destaque para a moqueca e o peixe na telha.', 'Av. Marginal, 200', '(14) 3604-3456', 'www.peixevivo.com', 'https://images.unsplash.com/photo-1519708227418-c8fd9a32b7a2?w=400&q=80', 5),
('Gastronomia', 'Cantina Italiana Bella Vista', 'Massas caseiras e pizzas artesanais com vista panorâmica.', 'Rua Italia, 78', '(14) 3604-7890', NULL, 'https://images.unsplash.com/photo-1555396273-367ea4eb4db5?w=400&q=80', 4),
('Gastronomia', 'Churrascaria do Rio', 'Rodízio de carnes nobres com buffet completo e música ao vivo aos finais de semana.', 'Av. Beira Rio, 500', '(14) 3604-2345', NULL, 'https://images.unsplash.com/photo-1558030006-450675393462?w=400&q=80', 5),
('Gastronomia', 'Café Colonial da Vó', 'Café colonial com mais de 30 opções de doces, salgados e bolos caseiros.', 'Praça Central, 12', '(14) 3604-6789', NULL, 'https://images.unsplash.com/photo-1521017432531-fbd92d768814?w=400&q=80', 4),
('Atividades', 'Aluguel de Barcos e Jet-skis', 'Aluguel de lanchas, jet-skis, caiaques e pedalinhos.', 'Marina Barra Bonita, Av. Beira Rio', '(14) 3604-1111', 'www.marinabarra.com', 'https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=400&q=80', 5),
('Atividades', 'Passeio de Escuna', 'Passeio guiado pelo Rio com parada para banho e almoço.', 'Píer Turístico', '(14) 3604-2222', NULL, 'https://images.unsplash.com/photo-1501854140801-50d01698950b?w=400&q=80', 5),
('Atividades', 'Trilhas Ecológicas', 'Trilhas monitoradas com guias especializados e observação de aves.', 'Recanto Ecológico', '(14) 3604-3333', NULL, 'https://images.unsplash.com/photo-1441974231531-c6227db76b6e?w=400&q=80', 4),
('Atividades', 'Pesca Esportiva', 'Passeios de barco para pesca com equipamentos e iscas inclusos.', 'Pesqueiro do Rio', '(14) 3604-4444', NULL, 'https://images.unsplash.com/photo-1500909019491-73dc3c1f8086?w=400&q=80', 4);
